def has_cycle(graph):
    """
    Belirtilen yönlü grafikte bir döngü olup olmadığını kontrol eder.

    Argümanlar:
        graph (dict): Komşuluk listesi olarak temsil edilen yönlü bir graf.
                      Anahtarlar düğümleri, değerler ise o düğümden çıkan 
                      kenarların ulaştığı düğümlerin listesidir.
                      Örn: {'A': ['B', 'C'], 'B': ['D'], 'C': [], 'D': []}

    Döngü varsa True, yoksa False döndürür.
    """
    visited = set()  # Tamamen ziyaret edilmiş ve işlenmiş düğümleri tutar
    recursion_stack = set()  # Mevcut DFS yolu üzerindeki düğümleri tutar (yineleme yığını)

    def dfs(node):
        visited.add(node)
        recursion_stack.add(node)

        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in recursion_stack:
                # Komşu zaten mevcut yineleme yığınındaysa bir döngü bulundu demektir.
                return True

        # Mevcut düğümün tüm komşuları kontrol edildi, 
        # bu düğümü yineleme yığınından çıkarabiliriz.
        recursion_stack.remove(node)
        return False

    # Grafikteki her düğüm için DFS'i çalıştırın
    # Bağlantısız bileşenleri de kapsamak için
    for node in graph:
        if node not in visited:
            if dfs(node):
                return True

    return False
